import UpSetJS, { extractCombinations } from '@upsetjs/react'
import { IGenes } from '../report'

export default function UpsetComponent(props: {
	geneValue: string[] | undefined
	genesListInfo: IGenes[]
}) {
	const { genesListInfo, geneValue } = props

	// const elem = genesListInfo
	// 	.filter((item: IGenes) => {
	// 		return (
	// 			geneValue?.includes(item.tool_name) ||
	// 			geneValue
	// 				?.map((value) => value.split('_')[1])
	// 				?.includes(item.gene_id)
	// 		)
	// 	})
	// 	.map((item: any) => ({
	// 		name: item.gene_id,
	// 		sets: [item.tool_name],
	// 	}))
	let genesObj: any = {}
	if (geneValue?.length) {
		genesListInfo.forEach((item: any) => {
			genesObj[item.gene_id] = { sets: [] }
			for (let toolName of [
				'coloc',
				'ecaviar',
				'fastenloc',
				'predixcan',
				'smr',
			]) {
				if (
					(geneValue
						?.map((item) => item.split('_')[1])
						?.includes(item.gene_id) &&
						geneValue
							?.map((item) => item.split('_')[0])
							?.includes(toolName)) ||
					(geneValue?.includes(toolName) && item[toolName] > -1)
				) {
					genesObj[item.gene_id].sets.push(toolName)
				}
			}
		})
	}
	let elem = []
	for (let gene in genesObj) {
		if (genesObj[gene].sets.length > 0)
			elem.push({ name: gene, sets: genesObj[gene].sets })
	}

	const { sets, combinations } = extractCombinations(elem, {
		type: 'distinctIntersection',
	})

	function setSelection(param: any) {}

	return (
		<>
			{elem.length > 0 && (
				<UpSetJS
					{...props}
					onHover={setSelection}
					sets={sets}
					combinations={combinations}
					width={500}
					height={300}
				/>
			)}
		</>
	)
}
