import { Table, Input, Tag, Card, Col, Row, Statistic, Select } from 'antd'
import { useEffect, useState } from 'react'
import { IGenes, ILocus, ITableItem } from '../report'
import {
	drawPlot,
	getJsonPData,
	GET_PLOTS_REPORT,
	localtionDir,
} from '../utils'
const { Search } = Input

const TOOL_SIG_COL_INFO: any = {
	coloc: 'overall_H4',
	smr: 'p_SMR',
	fastenloc: 'SCP',
	predixcan: 'pvalue',
	ecaviar: 'CLPP',
}

export default function LocusPlotComponent(props: {
	gene: Partial<IGenes> | any
	trait: string
	tissue: string
	population: string
	setLocusPreocess: any
}) {
	const { gene, trait, tissue, setLocusPreocess, population } = props
	// 存储一个gene的所有plot数据信息
	const [geneInfo, setGeneInfo] = useState<ILocus[]>([])
	const [dataSource, setDataSource] = useState<ITableItem[]>([])
	const [targetSnp, setTargetSnp] = useState<ILocus>()
	const [selectSnp, setSelectSnp] = useState<string>()
	const onChange = (value: string) => {
		console.log(`selected ${value}`)
		setSelectSnp(value)
	}

	const onSearch = (value: string) => {
		console.log('search:', value)
	}
	useEffect(() => {
		if (gene.gene_id && trait) {
			getJsonPData(
				GET_PLOTS_REPORT,
				`${trait}/${gene.gene_id}.json`
			).then((data: ILocus[]) => {
				setGeneInfo(data)

				setDataSource(
					data
						.filter((item) => item.category !== 'r2_one')
						.map((item, index) => {
							if (item.category === 'target') setTargetSnp(item)
							return {
								key: index,
								snp: item.snp,
								chromosome: item.chrom,
								position: item.position,
								y_axis: item.eqtl_pvalue,
								x_axis: item.pvalue,
								ldr2: item.r2,
							}
						})
				)
			})
		}
	}, [gene, trait])

	useEffect(() => {
		if (geneInfo.length > 0 && gene.gene_id) {
			let win: any = window
			setLocusPreocess('doing')
			drawPlot(
				() =>
					win.document.getElementById('gwas-plot') &&
					win.LocusZoomPlot.colocPlot(
						'#gwas-plot',
						geneInfo.map((item: ILocus) => {
							return {
								snp: item.snp,
								chrom: item.chrom,
								position: item.position,
								pvalue: item.pvalue,
								var_id: item.var_id_,
								category: item.category,
							}
						}),
						gene.gene_id,
						'gwas_plot',
						{
							tissue,
							trait,
						}
					)
			)
				.then(() =>
					drawPlot(() =>
						win.LocusZoomPlot.colocPlot(
							'#eqtl-plot',
							geneInfo.map((item: ILocus) => {
								return {
									snp: item.snp,
									chrom: item.chrom,
									position: item.position,
									pvalue: item.eqtl_pvalue,
									var_id: item.var_id_,
									category: item.category,
								}
							}),
							gene.gene_id,
							'eqtl_plot',
							{
								tissue,
								trait,
							}
						)
					)
				)
				.then(() =>
					drawPlot(() => {
						win.LocusZoomPlot.colocPlot(
							'#pvalue-plot',
							geneInfo.map((item: ILocus) => {
								return {
									snp: item.snp,
									chrom: item.chrom,
									position: item.pvalue,
									pvalue: item.eqtl_pvalue,
									var_id: item.var_id_,
									category: item.category,
								}
							}),
							gene.gene_id,
							'pvalue_plot',
							{
								tissue,
								trait,
							}
						)
						setLocusPreocess('')
					})
				)
		}
	}, [gene.gene_id, geneInfo, tissue, trait])

	const onSearchSnp = (value: string) => {
		setDataSource(
			geneInfo
				.filter((item) => item.category !== 'r2_one')
				.map((item, index) => {
					return {
						key: index,
						snp: item.snp,
						chromosome: item.chrom,
						position: item.position,
						y_axis: item.eqtl_pvalue,
						x_axis: item.pvalue,
						ldr2: item.r2,
					}
				})
				.filter((item: any) => {
					for (let key in item) {
						if (
							key !== 'key' &&
							(item[key].toString() as any).indexOf(value) > -1
						) {
							return true
						}
					}
					return false
				})
		)
	}

	const columns = [
		{
			title: 'rsID',
			dataIndex: 'snp',
			key: 'snp',
		},
		{
			title: 'Chromosome',
			dataIndex: 'chromosome',
			key: 'chromosome',
		},
		{
			title: 'Position',
			dataIndex: 'position',
			key: 'position',
		},
		{
			title: 'P-value(x-axis)',
			dataIndex: 'x_axis',
			key: 'x_axis',
		},
		{
			title: 'P-value(y-axis)',
			dataIndex: 'y_axis',
			key: 'y_axis',
		},
		{
			title: 'LD(r2)',
			dataIndex: 'ldr2',
			key: 'ldr2',
		},
	]

	const columns_gene = [
		{
			title: 'Tool Name',
			dataIndex: 'tool_name',
			key: 'tool_name',
		},
		{
			title: 'Tool report column name',
			dataIndex: 'type',
			key: 'type',
		},
		{
			title: 'value',
			dataIndex: 'value',
			key: 'value',
		},
	]

	return (
		<div>
			{gene.gene_id && (
				<Card>
					<Row gutter={16}>
						<Col span={9}>
							<Card style={{ height: '100%' }}>
								<Tag color='blue' style={{ width: '200px' }}>
									GENE information
								</Tag>
								<Statistic
									title='GENE ID'
									value={gene.gene_id}
								/>
								<Statistic
									title='GENE Symbol'
									value={gene.gene_name}
								/>
								<Statistic
									title='Chromosome'
									value={gene.chrom}
								/>
								<Statistic title='TSS' value={gene.position} />
							</Card>
						</Col>
						<Col span={15}>
							<Card>
								<Table
									dataSource={Object.keys(TOOL_SIG_COL_INFO)
										.filter(
											(toolName) => gene[toolName] > -1
										)
										.map((toolName) => {
											return {
												tool_name: toolName,
												type: TOOL_SIG_COL_INFO[
													toolName
												],
												value: gene[toolName],
											}
										})}
									columns={columns_gene}
								/>
							</Card>
						</Col>
					</Row>
				</Card>
			)}
			{gene.gene_id && (
				<Card>
					<div className='LocusWrapper'>
						<div id='pvalue-plot'></div>
						<div className='LocusPvalue'>
							<div className='LocusPvalueImg'></div>
						</div>
						<div>
							<div id='gwas-plot'></div>
							<div id='eqtl-plot'></div>
						</div>
					</div>
					<Card>
						<div className='selectSnpWrapper'>
							select snp:
							<Select
								className='snpSelectClass'
								showSearch
								placeholder='Select snp'
								optionFilterProp='children'
								onChange={onChange}
								onSearch={onSearchSnp}
								filterOption={(input, option) =>
									(option?.label ?? '')
										.toLowerCase()
										.includes(input.toLowerCase())
								}
								options={geneInfo.map((item) => {
									return {
										value: item.snp,
										label: item.snp,
									}
								})}
							/>
						</div>
						{selectSnp && (
							<Card className='codeClass'>
								<code>
									<a
										href='https://github.com/boxiangliu/locuscomparer'
										target='_blank'
										rel='noreferrer'
									>{`library(locuscomparer)`}</a>
								</code>
								<br />
								<code>{`gene_file <- read.csv("${
									localtionDir + trait
								}/${gene.gene_id}.tsv",TRUE,"\t")`}</code>
								<br />
								<code>{`locuscompare(in_fn1 = gene_file, in_fn2 = gene_file, pval_col1="pvalue", pval_col2="eqtl_pvalue", marker_col1="snp", marker_col2="snp", title1 = "${trait} GWAS", title2 = "${tissue} eQTL",snp="${selectSnp}", population="${population}")`}</code>
							</Card>
						)}
					</Card>
				</Card>
			)}
			{gene.gene_id && (
				<div className='tableWrapper'>
					<Row gutter={16}>
						<Col span={5}>
							<Card style={{ height: '100%' }}>
								<Tag color='blue' style={{ width: '200px' }}>
									SNP information
								</Tag>
								<Statistic
									title='Chromosome'
									value={targetSnp?.chrom}
								/>
								<Statistic
									title='Position'
									value={targetSnp?.position}
								/>
								<Statistic
									title='rs ID'
									value={gene.h_target_rsid}
								/>
								<Statistic
									title='Reference SNP'
									value={gene.ref}
								/>
								<Statistic
									title='Alternate SNP'
									value={gene.alt}
								/>
								<Statistic
									title='Allele Frequency'
									value={gene.AF}
								/>
								<Statistic
									title='AFR Frequency'
									value={gene.AFR_AF}
								/>
								<Statistic
									title='AMR Frequency'
									value={gene.AMR_AF}
								/>
								<Statistic
									title='EAS Frequency'
									value={gene.EAS_AF}
								/>
								<Statistic
									title='EUR Frequency'
									value={gene.EUR_AF}
								/>
								<Statistic
									title='SAS Frequenc'
									value={gene.SAS_AF}
								/>
							</Card>
						</Col>
						<Col span={19}>
							<Card>
								<Search
									className='searchInput'
									placeholder='input snp info'
									onSearch={onSearch}
									enterButton
								/>
								<Table
									dataSource={dataSource}
									columns={columns}
								/>
								;
							</Card>
						</Col>
					</Row>
				</div>
			)}
		</div>
	)
}
