import React, { useEffect, useState } from 'react'
import { IManhattan, MANHATTAN_FILE_NAME } from '../report'
import { getJsonPData, GET_MABHATTAN_REPORT } from '../utils'

function ManhattanPlotComponent(props: { trait: string }) {
	const { trait } = props

	useEffect(() => {
		if (trait)
			getJsonPData(
				GET_MABHATTAN_REPORT,
				`${trait}/${MANHATTAN_FILE_NAME}`
			).then((data: IManhattan[]) => {
				let win: any = window
				win.LocusZoomPlot.manhattanPlot(
					'#man-plot',
					data,
					(event: any) => {}
				)
			})
		return () => {
			let win: any = window
			if (win.document.getElementById('man-plot'))
				win.document.getElementById('man-plot').innerHTML = ''
		}
	}, [trait])

	return <div id='man-plot'></div>
}
const ManhattanPlotC = React.memo(ManhattanPlotComponent)
export default ManhattanPlotC
