import React, { FC, useCallback, useEffect, useMemo, useState } from 'react'
import './App.css'
import UpsetComponent from './component/UpsetComponent'
import {
	getJsonPData,
	GET_GENES_REPORT,
	GET_TOOLS_REPORT,
	parseTreeSelect,
} from './utils'

import * as _ from 'lodash'
import {
	Divider,
	Tag,
	Select,
	TreeSelect,
	Row,
	Col,
	Card,
	Collapse,
	Space,
} from 'antd'
import BarChartComponent from './component/BarChartComponent'
import * as ManhattanPlotComponent from './component/ManhattanPlotComponent'
import LocusPlotComponent from './component/LocuscPlotComponent'
import {
	GENES_FILE_NAME,
	IGenes,
	IReport,
	REPORTS_FILE_NAME,
	ITraitOption,
	ISelect,
} from './report'
const { SHOW_PARENT } = TreeSelect
const { Panel } = Collapse
const App: FC = () => {
	// report页面 traits, tissue, tools 汇总信息
	const [reportInfo, setReportInfo] = useState<IReport[]>([])
	// traits列表信息
	const [traitOption, setTraitOption] = useState<
		{ value: string; label: string; population: string }[]
	>([])
	// ranking列表信息
	const [modeOption, setModeOption] = useState<any>({})

	// 存储某个trait下所有gene信息
	const [genesListInfo, setGenesListInfo] = useState<IGenes[]>([])
	const [genesListSelectInfo, setGenesListSelectInfo] = useState<ISelect[]>(
		[]
	)

	// 存储当前选择的trait信息,默认选择列表第一个trait
	const [selectTrait, setSelectTrait] = useState<any>({})
	// 存储当前选择的gene信息
	const [geneListValue, setGeneListValue] = useState<string[]>([])

	// 存储当前选择的gene信息
	const [geneAndToolValue, setAndGeneToolValue] = useState<Partial<IGenes>>(
		{}
	)
	// 存储manhattan抽屉信息
	const [collapseNum, setCollapseNum] = useState<Partial<any>>([])
	// locus plot 进度
	const [locusPreocess, setLocusPreocess] = useState<any>()
	// gene list 选择设置
	const onChange = useCallback(
		(newValue: string[]) => {
			if (newValue.includes('all') && !geneListValue?.includes('all')) {
				setGeneListValue(genesListSelectInfo?.map((item) => item.value))
			} else if (
				!newValue.includes('all') &&
				geneListValue?.includes('all')
			) {
				setGeneListValue([])
			} else if (
				newValue.includes('all') &&
				geneListValue?.includes('all')
			) {
				setGeneListValue(newValue.filter((item) => item !== 'all'))
			} else {
				setGeneListValue(newValue)
			}
		},
		[geneListValue, genesListSelectInfo]
	)

	const tProps = useMemo(() => {
		return {
			treeData: genesListSelectInfo,
			value: geneListValue,
			onChange,
			treeCheckable: true,
			showArrow: true,
			showCheckedStrategy: SHOW_PARENT,
			placeholder: 'Please select',
		}
	}, [geneListValue, genesListSelectInfo, onChange])

	// 第一次界面需要显示的数据,默认选择列表第一个trait
	useEffect(() => {
		getJsonPData(GET_TOOLS_REPORT, REPORTS_FILE_NAME).then(
			(data: IReport[]) => {
				if (data.length > 0) {
					setReportInfo(data)
					setSelectTrait({
						value: data[0].trait + 0,
						label: data[0].trait,
						population: data[0].population,
					})
					getJsonPData(
						GET_GENES_REPORT,
						`${data[0].trait}/${GENES_FILE_NAME}`
					).then((data: IGenes[]) => {
						setModeOption({ value: 'geo', label: 'geo' })
						let rankFilteList = sortByRankType(data, 'geo')
						setGenesListInfo(rankFilteList)
						setGenesListSelectInfo(parseTreeSelect(rankFilteList))
					})
				}
			}
		)
	}, [])

	function sortByRankType(list: any, modeTyoe: any) {
		return _.sortBy(list, (item) =>
			modeTyoe === 'geo' ? -item.geo_p_value : item.geo_p_value
		).slice(0, 20)
	}

	// 根据report文件信息设置 trait select列表信息
	useEffect(() => {
		if (reportInfo.length > 0) {
			let options: ITraitOption[] = reportInfo.map(
				(item: IReport, index: number) => {
					return {
						value: item.trait + index,
						label: item.trait,
						population: item.population,
					}
				}
			)
			options = _.uniqBy(options, (o: ITraitOption) => o.label)
			setTraitOption(options)
		}
	}, [reportInfo])

	// 根据genes 汇总排名信息设置 gene select列表信息
	useEffect(() => {
		if (genesListSelectInfo.length > 0) {
			setGeneListValue(genesListSelectInfo?.map((item) => item.value))
		}
	}, [genesListSelectInfo])

	// 选择trait select
	const traitChange = useCallback(
		(_value: string, option: any) => {
			setSelectTrait(option)
			getJsonPData(
				GET_GENES_REPORT,
				`${option?.label}/${GENES_FILE_NAME}`
			).then((data: IGenes[]) => {
				let rankFilteList = sortByRankType(data, modeOption.value)
				setGenesListInfo(rankFilteList)
				setGenesListSelectInfo(parseTreeSelect(rankFilteList))
				setAndGeneToolValue({})
				setCollapseNum([])
			})
		},
		[modeOption.value]
	)

	const onCollapseChange = (key: any) => {
		if (locusPreocess !== 'doing') setCollapseNum(key)
	}

	const modeChange = useCallback(
		(key: string | string[]) => {
			setModeOption({ value: key, label: key })
			let rankFilteList = sortByRankType(genesListInfo, key)
			setGenesListInfo(rankFilteList)
			setGenesListSelectInfo(parseTreeSelect(rankFilteList))
			setAndGeneToolValue({})
		},
		[genesListInfo]
	)

	return (
		<div className='App'>
			<Divider orientation='left'></Divider>
			<div className='StudyWrapper'>
				<Row>
					<Col span={12}>
						<Row className='TagRow'>
							<Space size={'small'}>
								<Col>GWAS study</Col>
								<Col>
									<Tag color='blue' className='StudyTitle'>
										{reportInfo[0] &&
											reportInfo[0]['study1']}
									</Tag>
								</Col>
							</Space>
						</Row>
						<Row className='TagRow'>
							<Space size={'small'}>
								<Col>eQTL tissue</Col>
								<Col>
									<Tag color='blue' className='StudyTitle'>
										{reportInfo[0] &&
											reportInfo[0]['tissue']}
									</Tag>
								</Col>
							</Space>
						</Row>
						<Row className='TagRow'>
							<Space size={'small'}>
								<Col>population</Col>
								<Col>
									<Tag color='blue' className='StudyTitle'>
										{selectTrait.population}
									</Tag>
								</Col>
							</Space>
						</Row>
					</Col>
					<Col span={12}>
						<Row className='TagRow'>
							<Space size={'small'}>
								<Col>select trait</Col>
								<Col>
									<Select
										showSearch
										value={selectTrait.value}
										className='StudySelect'
										placeholder='Search trait'
										optionFilterProp='children'
										filterOption={(input, option: any) =>
											(option?.label ?? '').includes(
												input
											)
										}
										filterSort={(optionA, optionB) =>
											(optionA?.label ?? '')
												.toLowerCase()
												.localeCompare(
													(
														optionB?.label ?? ''
													).toLowerCase()
												)
										}
										options={traitOption}
										onChange={traitChange}
									/>
								</Col>
							</Space>
						</Row>
						<Row className='TagRow'>
							<Space size={'small'}>
								<Col>select rank mode</Col>
								<Col>
									<Select
										showSearch
										value={modeOption.value}
										className='StudySelect'
										placeholder='Search trait'
										optionFilterProp='children'
										filterOption={(input, option: any) =>
											(option?.label ?? '').includes(
												input
											)
										}
										filterSort={(optionA, optionB) =>
											(optionA?.label ?? '')
												.toLowerCase()
												.localeCompare(
													(
														optionB?.label ?? ''
													).toLowerCase()
												)
										}
										options={[
											{ value: 'geo', label: 'geo' },
											{
												value: 'intact',
												label: 'intact',
											},
										]}
										onChange={modeChange}
									/>
								</Col>
							</Space>
						</Row>
						<Row className='TagRow'>
							<Space size={'small'}>
								<Col>select gene</Col>
								<Col>
									<TreeSelect
										{...tProps}
										treeDefaultExpandAll
										className='StudySelect'
									/>
								</Col>
							</Space>
						</Row>
					</Col>
				</Row>
			</div>

			<div className='StudyWrapper'></div>

			<div>
				<div className='firstRowPlot'>
					<Row>
						<Col span={12} style={{ padding: 0 }}>
							<Card style={{ height: '100%' }}>
								<UpsetComponent
									geneValue={geneListValue}
									genesListInfo={genesListInfo}
								></UpsetComponent>
							</Card>
						</Col>
						<Col span={12} style={{ padding: 0 }}>
							<Card style={{ height: '100%' }}>
								<BarChartComponent
									geneValue={useMemo(
										() => geneListValue,
										[geneListValue]
									)}
									plotData={useMemo(
										() => genesListInfo,
										[genesListInfo]
									)}
									modeOption={useMemo(
										() => modeOption,
										[modeOption]
									)}
									setAndGeneToolValue={useCallback(
										(gene_id: string) => {
											setAndGeneToolValue(
												genesListInfo.filter(
													(item) =>
														item.gene_id === gene_id
												)[0]
											)
										},
										[genesListInfo]
									)}
								/>
							</Card>
						</Col>
					</Row>
				</div>
				<div>
					<Card>
						<Collapse
							defaultActiveKey={[]}
							activeKey={collapseNum as any}
							onChange={onCollapseChange}
						>
							<Panel header='GWAS Manhattan Plot' key='1'>
								<ManhattanPlotComponent.default
									trait={useMemo(
										() => selectTrait.label,
										[selectTrait.label]
									)}
								/>
							</Panel>
						</Collapse>
					</Card>
					<LocusPlotComponent
						tissue={reportInfo[0] && reportInfo[0]['tissue']}
						trait={selectTrait.label}
						gene={geneAndToolValue}
						population={selectTrait.population}
						setLocusPreocess={setLocusPreocess}
					/>
				</div>
			</div>
		</div>
	)
}

export default App
