import React, { useEffect } from 'react'
import * as echarts from 'echarts'
import { IGenes, ITraitOption } from '../report'
import * as _ from 'lodash'
import { Button } from 'antd'

export default React.memo(function BarChartComponent(props: {
	plotData: IGenes[]
	geneValue: string[]
	modeOption: any
	setAndGeneToolValue: (geng_id: string) => void
}) {
	const { plotData, geneValue, setAndGeneToolValue, modeOption } = props
	useEffect(() => {
		let win: any = window
		if (!!geneValue?.length) {
			console.log('change', geneValue)
			win.LocusZoomPlot.manhattanPlot(
				'#gene-plot',
				plotData
					.filter((item: any) => {
						return (
							geneValue?.filter((value) => item[value])[0] ||
							geneValue
								?.map((value) => value.split('_')[1])
								?.includes(item.gene_id)
						)
					})
					.map((item: IGenes) => {
						return {
							snp: item.gene_id,
							chrom: item.chrom,
							position: item.position,
							pvalue:
								modeOption.value === 'geo'
									? item.geo_p_value
									: item.intact_probability,
							var_id: item.gene_name,
							category: '',
						}
					}),
				(event: any) => {
					setAndGeneToolValue(event.snp)
				},
				'gene_type'
			)
		}
	}, [geneValue, modeOption.value, plotData, setAndGeneToolValue])

	return (
		<>
			{!!geneValue?.length && (
				<div className='geneWrapper' id='gene-plot'></div>
			)}
		</>
	)
})
